SELECT product_id, stock_level
FROM inventory
ORDER BY stock_level DESC;

SELECT AVG(i.stock_level) AS average_stock_level
FROM inventory i
INNER JOIN analytics a ON i.product_id = a.product_id;

SELECT customer_id 
FROM customers 
WHERE preferred_size_standard IN (
    SELECT DISTINCT converted_size_standard 
    FROM analytics
) 
AND customer_id NOT IN (
    SELECT DISTINCT customer_id 
    FROM customer_feedback
);

SELECT product_id, size_standard, size_value, stock_level, inventory_status
FROM inventory
ORDER BY stock_level DESC;

SELECT DISTINCT p.product_name
FROM products p
INNER JOIN analytics a ON p.product_id = a.product_id;
